use distributed_inference::pleromatic_frame::PleromaticFrame;
use std::path::PathBuf;

fn parse_arg(name: &str, default: &str) -> String {
    let mut args = std::env::args().skip(1);
    while let Some(a) = args.next() {
        if a == name {
            return args.next().unwrap_or_else(|| default.to_string());
        }
    }
    default.to_string()
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let width = parse_arg("--width", "2080").parse::<usize>()?;
    let height = parse_arg("--height", "240").parse::<usize>()?;
    let freq_hz = parse_arg("--freq-hz", "137100000").parse::<u64>()?;
    let output = PathBuf::from(parse_arg("--out", "noaa_apt.frame"));
    let source = parse_arg("--source", "noaa15-sim");

    let mut data = vec![0u8; width * height];
    for y in 0..height {
        for x in 0..width {
            // REALISTIC NOAA APT ARCHITECTURE (2080 px width):
            // [Sync A: 39] [Space: 47] [Image A: 909] [Tele A: 45] [Sync B: 39] [Space: 47] [Image B: 909] [Tele B: 45]

            let val = if x < 39 {
                // Sync A (Pulse)
                if (x + y / 2) % 4 < 2 {
                    255
                } else {
                    0
                }
            } else if x < 86 {
                // Pre-img A
                40
            } else if x < 995 {
                // Image A (Gradient/Terrain)
                let terrain = (x as f32 * 0.1).sin() * 20.0;
                (128.0 + terrain + (y as f32 * 0.05).cos() * 30.0) as u8
            } else if x < 1040 {
                // Telemetry A
                if (y / 16) % 2 == 0 {
                    200
                } else {
                    50
                }
            } else if x < 1079 {
                // Sync B
                if (x + y / 4) % 8 < 4 {
                    180
                } else {
                    20
                }
            } else if x < 1126 {
                // Pre-img B
                40
            } else if x < 2035 {
                // Image B (Infrared)
                let clouds = (x as f32 * 0.05 + y as f32 * 0.02).sin() * 50.0;
                (100.0 + clouds) as u8
            } else {
                // Telemetry B
                if (y / 32) % 2 == 0 {
                    220
                } else {
                    30
                }
            };

            data[y * width + x] = val;
        }
    }

    let frame = PleromaticFrame::noaa_apt_scanlines(source, width, height, data, Some(freq_hz));
    let bytes = bincode::serialize(&frame)?;
    std::fs::write(&output, bytes)?;
    println!(
        "wrote {} ({}x{}, freq={}Hz)",
        output.display(),
        width,
        height,
        freq_hz
    );
    Ok(())
}
